sp_widget.client_script:
api.controller=function($scope, $filter, spUtil, spModal) {
  /* widget controller */
  var c = this;

	$scope.loadingData = true;
	var loadRowCount = c.data.row_count;
	_loadData();

	spUtil.recordWatch($scope, c.data.table, c.data.filter, function(name) {
		$scope.loadingData = true;
		_loadData();
	});

	function _loadData(){
		$scope.server.update().then(function() {
			$scope.loadingData = false;
		});		
	}

	/*** 2.8.1 | 2023-01-25 | mmcc | DFCT0011473 - OOO Schedule Row Item Menu is cut off ***/
	// Make sure all other tooltips are closed except for the 1 passed in, no stuck open tooltips
	function _closeOtherTooltips(tooltipItem) {
        c.data.list.forEach(function(rowItem) {
            if (tooltipItem.sys_id !== rowItem.sys_id) {
                rowItem.isRowItemMenuOpen = false;
            }
        });
    }

	// 2.8.1 | 2023-01-25 | mmcc | DFCT0011473 - OOO Schedule Row Item Menu is cut off; added function to toggle boolean value
	c.rowItemMenuClicked = function(item) {
		item.isRowItemMenuOpen = !item.isRowItemMenuOpen;
		_closeOtherTooltips(item);
	};

	// *******************************************
	// START EDIT OOO MENU OPTION
	// *******************************************
	$scope.editOOO = function(item) {
		// 2.8.1 | 2023-01-25 | mmcc | DFCT0011473 - OOO Schedule Row Item Menu is cut off; close the row item menu
		item.isRowItemMenuOpen = false;
		spModal.open({
			// DFCT0011638
			title: c.data.table_label,
			message: '',
			backdrop: 'static',
			widget: 'discovertasker-formtab',
			widgetInput: {
				table: c.data.table,
				sys_id: item.sys_id,
				hideRelatedLists: false,
				omitHeader: true,
				bifold: false,
				hideAttachmentBtn: true,
				isModal: true
			},
			shared: {},
			size: 'lg',
			buttons: [],
			footerStyle: {
				'display': 'none'
			}
		});
	};
	// *******************************************
	// END EDIT OOO MENU OPTION
	// *******************************************

	// *******************************************
	// START DELETE OOO MENU OPTION
	// *******************************************
	$scope.deleteOOO = function(item) {
		var startDate = item.startDateLong; //formatDate(item.u_start_date.display_value.substring(0,10), 'MMMM d, yyyy');
		var endDate = item.endDateLong; //formatDate(item.u_end_date.display_value.substring(0,10), 'MMMM d, yyyy');

		// 2.8.1 | 2023-01-25 | mmcc | DFCT0011473 - OOO Schedule Row Item Menu is cut off; close the row item menu
		item.isRowItemMenuOpen = false;

		spModal.open({
            title: c.data.deleteTitle,
            backdrop: 'static',
            widget: 'tasker_modal_delete_prompt',
            widgetInput: {
							'oooSysId': item.sys_id,
							'oooStartDate': startDate,
							'oooEndDate': endDate
            },
            buttons: [],
			// Hide the <div> with class modal-footer that gets auto inserted from spModal, adds an element style
			footerStyle: { 'display': 'none' }
        }).then(function() {
            //jslog('numberofsubtasks');
        });
	};
	// *******************************************
	// END DELETE OOO MENU OPTION
	// *******************************************

	// *******************************************
	// START VIEW HISTORY OOO MENU OPTION
	// *******************************************
	$scope.viewHistory = function(item){
		$scope.$emit("$oooViewHistory");
	};
	// *******************************************
	// END VIEW HISTORY OOO MENU OPTION
	// *******************************************
};

sp_widget.css:
/* Hide uib tooltip arrow */
.tooltip.rowItemMenuCss .tooltip-arrow {
  display: none;
}

/* Change arrow color */
/*  .tooltip.rowItemMenuCss .tooltip-arrow {
border-bottom-color: #FFFFFF;
}
*/

.tooltip.rowItemMenuCss .tooltip-inner .divider {
  background-color: #D9D9D9;
  height: 1px;
  /* margin: 9px 0; */
  overflow: hidden;
}

/* Override default of opacity: .9 because tooltip-animation="false" does not seem to work */
.tooltip.in {
  opacity: 1;
}

/* Specify styling for tooltip contents */
.tooltip.rowItemMenuCss .tooltip-inner {
  background-color: #FFF;
  box-shadow: 0 6px 12px rgba(0,0,0,.175);
  color: #000000;
  font-size: 14px;
  padding: 0;
}

.tooltip.rowItemMenuCss .tooltip-inner > ul {
  margin-bottom: 0;
  margin-top: 0;
}

.rowitem-menulist > li > a {
  background-color: transparent;
  color: #000000;
  display: block;
}

.rowitem-menulist > li > a:hover {
  background-color: #D9EDF7;
  box-shadow:0px 0px 0px 2px #D9EDF7 inset;
  cursor: pointer;
}

.rowitem-menulist > li > a:focus {
  /*background-color: transparent;*/
  box-shadow:0px 0px 0px 2px #00A4FF inset;
  /*color: #000000; */
}


.ooo-scheduled-row {
  width: 100%;
  height: 80px;
  background-color: #f5f5f5;
  border-radius: 10px;
  box-shadow:0px 0px 0px 2px #f5f5f5 inset;
} 

.ooo-scheduled-row:hover {
  background-color: #d9edf7;
  box-shadow:0px 0px 0px 2px #d9edf7 inset;
  cursor: pointer;
}

.ooo-scheduled-row:focus {
  box-shadow:0px 0px 0px 2px #00A4FF inset;
}

.ooo-scheduled-row:active {
  background-color: #d9edf7;
  box-shadow:0px 0px 0px 2px #d9edf7 inset;
}

.ooo-scheduled-row:disabled {
  background-color: #f5f5f5;
}

.ooo-scheduled-columnheader {
  /* 2.8.1 | 2023-01-25 | mmcc | DFCT0011473 - OOO Schedule Row Item Menu is cut off; no need to override <body> tag defaults
  font-family: SourceSansPro, Helvetica, Arial, sans-serif;
  font-size: 14px;*/
  color: #757575;
  padding: 10px 0px 0px 10px;
}

.ooo-scheduled-columnheader:disabled {
  color: #757575;
  padding: 10px 0px 0px 10px;
}

.ooo-scheduled-datelabel {
  /* 2.8.1 | 2023-01-25 | mmcc | DFCT0011473 - OOO Schedule Row Item Menu is cut off; no need to override <body> tag defaults
  font-family: SourceSansPro, Helvetica, Arial, sans-serif; 
  font-size: 14px;*/
  color: #000000; 
  font-weight: 600;
  padding: 0px 0px 0px 10px;
}

.ooo-scheduled-datelabel:disabled {
  color: #757575;
}

.ooo-scheduled-ellipsesbtn {
  width: 24px;
  height: 24px;
  padding-right:20px;
  padding-left:20px;
  vertical-align: middle;
  background-color: #f5f5f5;
  border-radius: 5px;
  box-shadow:0px 0px 0px 2px #f5f5f5 inset;
}

.ooo-scheduled-ellipsesbtn:hover {
  background-color: #d9edf7;
  box-shadow:0px 0px 0px 2px #d9edf7 inset;
  cursor: pointer;
}

.ooo-scheduled-ellipsesbtn:focus {
  box-shadow:0px 0px 0px 2px #00A4FF inset;
}

.ooo-scheduled-ellipsesbtn:active {
  background-color: #d9edf7;
  box-shadow:0px 0px 0px 2px #d9edf7 inset;
}

