// Script Continued Below
//------------------------------------------------------------------------------------------------------------------------
// COMPANY: DISCOVER TECHNOLOGIES
// WIDGET BASE: 
//------------------------------------------------------------------------------------------------------------------------
// 2.8.1 | 2022-11-10 | raj  | STRY0132270 - Tasker User Profile- New Component- "Out of Office Schedule" - OOO Scheduled Widget
//                                      New Widget
// 2.8.1 | 2022-11-12 | raj  | STRY0131195 - Delete OOO Schedule Confirmation Modal
//                                         Changes made in Server Script, Client Script, opened the tasker delete prompt widget from delete click
// 2.8.1 | 2023-01-11 | mmcc | DFCT0011540 - "View my History" choice menu should NOT display on the "Scheduled Out of Office" 
//                                      record when clicking on the "Ellipses"
//                                      In HTML, comment out li tag for View History
//                                      Changes made in HTML.
// 2.8.1 | 2023-01-25 | mmcc | DFCT0011473 - OOO Schedule Row Item Menu is cut off when 1 row or last row after clicking on the "Ellipsis"
//                                      In HTML, Removed dropdown-menu, added uib tooltip
//                                      In CSS, Removed dropdown-menu, added rowitem-menulist and .tooltip.rowItemMenuCss
//                                      In Server script, in _loadScheduledOOO() added setting isRowItemMenuOpen
//                                      In Client controller, added _closeOtherTooltips() and rowItemMenuClicked(); edit000() and deleteOOO() sets bool 
//                                        isRowItemMenuOpen
//                                      Changes made in HTML, CSS, Server script and Client controller.
// 2.8.1 - 2022-03-23 - raj  -  DFCT0011638 - Edit Existing Out of Office Modal's [ACL; Title; Action Button] do not match story
//																			Changes in Client Script and Server Script
// 2.8.1 - 2022-03-24 - raj  -  DFCT0011617 - Existing Task form >"Show me all the Out of Office Schedules...">Tasker User Settings Container modal> does NOT display Scheduled Out of Office on the list view
//																			Changes in HTML only
//
//------------------------------------------------------------------------------------------------------------------------

(function($sp, input, data, options, gs) {
	main();

	function main() {

		data.isModal = (input || {}).isModal || (options || {}).isModal || $sp.getParameter("isModal") || false;
		data.isTopWidget = (input || {}).isTopWidget || (options || {}).isTopWidget || $sp.getParameter("isTopWidget") || false;
		data.bifold = (input || {}).bifold || (options || {}).bifold || $sp.getParameter("bifold") || false;
		data.user = (input || {}).user || (options || {}).user || $sp.getParameter("user_id") || gs.getUserID();
		data.table = "x_153465_discovert_out_of_office";
		data.list = [];
		data.fields = "u_start_date,u_end_date,sys_created_on,sys_updated_on,u_out_of_office_message";
		data.fields_array = data.fields.split(',');
		data.column_labels = {};
		data.filter = "^u_user=" + data.user + "^u_end_date>=javascript:gs.endOfToday()";

		data.column_labels = _loadColumnLabels();
		data.list = _loadScheduledOOO();
		data.canCreateOOO = new Organization_uiAction().canCreateOOO(data.user);

		_getMessages();

		// 2.8.1 | 2023-01-25 | mmcc | DFCT0011473 - OOO Schedule Row Item Menu is cut off; added call to convertToBool()
		convertToBool(['bifold', 'isModal', 'isTopWidget']);
	}

	function _getMessages(){
		data.ellipsesIcon = "Ellipses16.svg";
		data.editIcon = "Edit16.svg";
		data.deleteIcon = "Delete16.svg";
		data.historyIcon = "History16.svg";
		data.deleteTitle = gs.getMessage("Tasker - Confirm Delete Schedule");
	}

	function _loadScheduledOOO(){
		var list = [];
		var gr_ooo = new GlideRecordSecure(data.table);
		// DFCT0011638
		data.table_label = gr_ooo.getLabel();

		gr_ooo.addEncodedQuery(data.filter);
		gr_ooo.query();

		while(gr_ooo.next()){
			data.canWrite = gr_ooo.canWrite();
			data.canDelete = gr_ooo.canDelete();

			var record = {};
			$sp.getRecordElements(record,gr_ooo,data.fields);
			record.sys_id = gr_ooo.getValue('sys_id');

			var gDateStart = new GlideDate();
			gDateStart.setDisplayValue(gr_ooo.getDisplayValue("u_start_date"));
			record.startDateLong =  gDateStart.getByFormat('MMMM d, y');//now use the date2 to set the field value
			var gDateEnd = new GlideDate();
			gDateEnd.setDisplayValue(gr_ooo.getDisplayValue("u_end_date"));
			record.endDateLong =  gDateEnd.getByFormat('MMMM d, y');//now use the date2 to set the field value

			//  2.8.1 | 2023-01-25 | mmcc | DFCT0011473 - OOO Schedule Row Item Menu is cut off; add data to show/hide tooltip
			record.isRowItemMenuOpen = false;

			list.push(record);
		}
		return list;
	}

	function _loadColumnLabels(){
		var column_labels = {};
    // use GlideRecord to get field labels vs. GlideRecordSecure
    var grForLabels = new GlideRecord(data.table);
    for (var i in data.fields_array) {
        var field = data.fields_array[i];
        var ge = grForLabels.getElement(field);

        //---------------------------------------------
        //STRY0071963: Servcienow Server JavaScript error getLabel in object null.
        /*if (ge == null)
        	continue;

        column_labels[field] = ge.getLabel();
        */
        try {
            if (ge == null)
                continue;

            column_labels[field] = ge.getLabel();
        } catch (ex) {
            var message = ex.message;
            gs.error("Tasker error in Scheduled Out of Office Widget - field : " + message + " | field: " + field + " | ge: " + ge + " | i :" + i);
        }
        //---------------------------------------------
    }
		return column_labels;

	}

	// copy to data from input or options
	function optCopy(names) {
		names.forEach(function(name) {
			data[name] = input[name] || options[name];
		});
	}

	function convertToBool(names) {
		names.forEach(function(name) {
			data[name] = data[name] == true || data[name] == 'true';
		});
	}
})($sp, input, data, options, gs);
